// Human-readable description for each skill modifier, surfaced as
// the chip's aria-label + title + sr-only text. Lets screen
// readers and keyboard users learn what the chip means instead
// of hearing the raw short name.
//
// Source: Booster Helmet wiki. Knowledge Caps grant a 10% boost
// in Skill Exp when worn (rewarded by finishing 1st in a Weekly
// Challenge of the matching skill). Christmas Caps are awarded
// rarely through Christmas Events and grant a 2.5% boost in
// Skill Exp plus a 1.5% boost in Skill Money.
//
// The modifier alone doesn't tell the two cap variants apart,
// so the description covers both cases.
function modifierDescription(skill) {
  return `${skill} modifier — passive boost to ${skill} when worn. Knowledge Cap: 10% Skill Exp. Christmas Cap: 2.5% Skill Exp + 1.5% Skill Money.`;
}

// Tier description: 1 = base stat, 2 = mid-tier (better stats),
// 3 = top-tier (best stats). Surfaced as the chip's aria-label
// + sr-only text so the screen reader can convey rarity.
const TIER_DESCRIPTION = {
  1: "Tier 1 — base stats",
  2: "Tier 2 — improved stats",
  3: "Tier 3 — top-tier stats",
};

const MODIFIER_COLORS = {
  Hunting:    "border-emerald-500/30 text-emerald-300 bg-emerald-500/10",
  Mining:     "border-amber-500/30 text-amber-300 bg-amber-500/10",
  Woodcutting:"border-lime-500/30 text-lime-300 bg-lime-500/10",
  Fishing:    "border-cyan-500/30 text-cyan-300 bg-cyan-500/10",
  Farming:    "border-green-500/30 text-green-300 bg-green-500/10",
  Smelting:   "border-orange-500/30 text-orange-300 bg-orange-500/10",
};

// Tier chip palette — matches tierClass() text colors, with a translucent
// background so it reads as a real chip, not text in parens. Each tier
// gets the same hue it had before (T1=emerald, T2=amber, T3=red).
const TIER_CHIP = {
  1: "border-emerald-500/30 text-emerald-300 bg-emerald-500/10",
  2: "border-amber-500/30 text-amber-300 bg-amber-500/10",
  3: "border-red-500/30 text-red-300 bg-red-500/10",
};

export default function ItemName({ name, tier, modifiers, showModifiers = true, className = "", layout = "inline" }) {
  const match = name?.match(/^(.*?)\s*\(T([123])\)$/);
  const base = match ? match[1] : name;
  const tierNum = match ? match[2] : (tier && tier > 0 ? String(tier) : null);
  const list = modifiers && modifiers.length > 0 ? modifiers : null;

  // The chip(s) are rendered as a separate fragment so the layout
  // prop can decide whether they sit next to the name (inline), wrap
  // under it (wrap, used in long-name rows), or stack on their own
  // line below the name (stack, used in tight cards like RecentlyViewed).
  //
  // Each chip is focusable (tabIndex=0) and carries an aria-label +
  // sr-only description so screen-reader and keyboard-only users
  // get the same information sighted users get from the color +
  // short label.
  const chips = (
    <>
      {tierNum && (
        <span
          data-testid={`tier-tag-T${tierNum}`}
          tabIndex={0}
          role="img"
          aria-label={TIER_DESCRIPTION[tierNum] || `Tier ${tierNum}`}
          title={TIER_DESCRIPTION[tierNum] || `Tier ${tierNum}`}
          className={`shrink-0 inline-flex items-center font-mono text-[11px] font-bold uppercase tracking-[0.15em] px-2 py-0.5 rounded border focus:outline-none focus:ring-1 focus:ring-emerald-400 ${TIER_CHIP[tierNum] || "border-white/15 text-zinc-300 bg-white/[0.04]"}`}
        >
          T{tierNum}
          <span className="sr-only"> {TIER_DESCRIPTION[tierNum] || ""}</span>
        </span>
      )}
      {showModifiers && list && list.map((m) => {
        const desc = modifierDescription(m);
        return (
          <span
            key={m}
            data-testid={`modifier-tag-${m.toLowerCase()}`}
            tabIndex={0}
            role="img"
            aria-label={desc}
            title={desc}
            className={`shrink-0 inline-flex items-center font-mono text-[11px] font-semibold uppercase tracking-[0.15em] px-2 py-0.5 rounded border focus:outline-none focus:ring-1 focus:ring-emerald-400 ${MODIFIER_COLORS[m] || "border-white/15 text-zinc-300 bg-white/[0.04]"}`}
          >
            {m}
            <span className="sr-only"> {desc}</span>
          </span>
        );
      })}
    </>
  );

  if (layout === "stack") {
    // Name on line 1 (truncates with ellipsis), chips on line 2 below
    // the name. Use min-w-0 + truncate so a long name doesn't push
    // the card wider. Row-gap 4px gives a small visual breath.
    return (
      <span className={`inline-flex flex-col items-start gap-1 min-w-0 max-w-full ${className}`}>
        <span className="truncate max-w-full">{base}</span>
        <span className="inline-flex items-center gap-1 flex-wrap">{chips}</span>
      </span>
    );
  }

  if (layout === "wrap") {
    // Name + chips flow inline but can wrap to a second line as a
    // unit if the container is too narrow. The name keeps its full
    // text (no truncate) so it never breaks mid-word, and chips
    // always stay attached to the name.
    return (
      <span className={`inline-flex items-center gap-1.5 flex-wrap min-w-0 ${className}`}>
        <span className="whitespace-nowrap max-w-full overflow-hidden">{base}</span>
        <span className="inline-flex items-center gap-1.5 flex-wrap">{chips}</span>
      </span>
    );
  }

  // "inline" (default): name truncates with ellipsis if it would
  // overflow; chips sit next to it and never wrap. Best for rows
  // where the name has fixed space and the chips are always visible.
  return (
    <span className={`inline-flex items-center gap-1.5 min-w-0 ${className}`}>
      <span className="truncate">{base}</span>
      {chips}
    </span>
  );
}
